	'#': { DataType: 'Numeric', Label: 'Numeric', HasSize: false },
	'.': { DataType: 'Decimal', Label: 'Decimal', HasSize: true },
	'&': { DataType: 'DateTime', Label: 'Date/Time', HasSize: false },
